import React, { useEffect, useState } from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";

const BusTrendChart = ({ buses }) => {
  const [trendData, setTrendData] = useState([]);

  useEffect(() => {
    const now = new Date();
    const timeLabel = now.toLocaleTimeString();

    const activeCount = buses?.filter(b => b.status === "active").length || 0;
    const ghostCount = buses?.filter(b => b.status === "ghost").length || 0;

    // Add new data point
    setTrendData(prevData => [
      ...prevData,
      { time: timeLabel, active: activeCount, ghost: ghostCount }
    ]);

    // Keep only last 20 points to avoid long list
    if (trendData.length > 20) {
      setTrendData(prevData => prevData.slice(prevData.length - 20));
    }

  }, [buses]); // update whenever buses change

  return (
    <div
      style={{
        width: "90%",
        margin: "20px auto",
        backgroundColor: "white",
        padding: "10px",
        borderRadius: "8px",
        zIndex: 1000,
      }}
    >
      <LineChart width={800} height={250} data={trendData}>
        <XAxis dataKey="time" />
        <YAxis />
        <Tooltip />
        <CartesianGrid stroke="#f5f5f5" />
        <Line type="monotone" dataKey="active" stroke="green" />
        <Line type="monotone" dataKey="ghost" stroke="red" />
      </LineChart>
    </div>
  );
};

export default BusTrendChart;
